async function generateVoiceLine(speaker: "Aleks" | "Nicole", text: string) {
    const voice = speaker === "Aleks" ? "alloy" : "nova";
    const response = await client.audio.speech.create({
        model: "tts-1-hd",
        voice,
        input: text,
    });
