rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {
    match /tokens/{id}/{u=**} {
      allow read, write: if (isSignedIn() && isUser(id));
    }
    match /{document=**} {
      allow read, write: if false;
    }
    function isSignedIn() {
      return request.auth != null;
    }

    function isUser(uid) {
      return uid == request.auth.uid;
    }
  }
}
